// handleRegistry tracks cgo.Handles by name to ensure proper cleanup on unregister.
// Without this, unregistered plugins can cause use-after-free crashes when Rust
// still holds vtable pointers and tries to invoke callbacks on deleted handles.
type handleRegistry struct {
	mu      sync.Mutex
	handles map[string]cgo.Handle
}

var (
	ocr_backendRegistry        = &handleRegistry{handles: make(map[string]cgo.Handle)}
	post_processorRegistry     = &handleRegistry{handles: make(map[string]cgo.Handle)}
	validatorRegistry          = &handleRegistry{handles: make(map[string]cgo.Handle)}
	document_extractorRegistry = &handleRegistry{handles: make(map[string]cgo.Handle)}
	embedding_backendRegistry  = &handleRegistry{handles: make(map[string]cgo.Handle)}
	rendererRegistry           = &handleRegistry{handles: make(map[string]cgo.Handle)}
	reranker_backendRegistry   = &handleRegistry{handles: make(map[string]cgo.Handle)}
	tokenizer_backendRegistry  = &handleRegistry{handles: make(map[string]cgo.Handle)}
)

// store adds a handle to the registry, keyed by name.
func (reg *handleRegistry) store(name string, handle cgo.Handle) {
	reg.mu.Lock()
	defer reg.mu.Unlock()
	if old, ok := reg.handles[name]; ok {
		old.Delete()
	}
	reg.handles[name] = handle
}

// delete removes and deletes a handle from the registry by name.
func (reg *handleRegistry) delete(name string) {
	reg.mu.Lock()
	defer reg.mu.Unlock()
	if handle, ok := reg.handles[name]; ok {
		delete(reg.handles, name)
		handle.Delete()
	}
}

// clear removes and deletes all handles from the registry.
func (reg *handleRegistry) clear() {
	reg.mu.Lock()
	defer reg.mu.Unlock()
	for _, handle := range reg.handles {
		handle.Delete()
	}
	reg.handles = make(map[string]cgo.Handle)
}

// OcrBackend defines the Go interface for the OcrBackend trait.
type OcrBackend interface {
	// Name returns the plugin name.
	Name() string
	// Version returns the plugin version.
	Version() string
	// Initialize is called when the plugin is loaded.
	Initialize() error
	// Shutdown is called when the plugin is unloaded.
	Shutdown() error
	// process_image
	ProcessImage(image_bytes []byte, config OcrConfig) (ExtractedDocument, error)

	// process_image_file
	ProcessImageFile(path string, config OcrConfig) (ExtractedDocument, error)

	// supports_language
	SupportsLanguage(lang string) bool

	// backend_type
	BackendType() OcrBackendType

	// supported_languages
	SupportedLanguages() []string

	// supports_table_detection
	SupportsTableDetection() bool

	// supports_document_processing
	SupportsDocumentProcessing() bool

	// emits_structured_markdown
	EmitsStructuredMarkdown() bool

	// process_document
	ProcessDocument(_path string, _config OcrConfig) (ExtractedDocument, error)
}

// OcrBackendBridge wraps a OcrBackend implementation and exposes it to the C plugin system.
type OcrBackendBridge struct {
	impl OcrBackend
}

// NewOcrBackendBridge creates a new Bridge wrapping the given implementation.
func NewOcrBackendBridge(impl OcrBackend) *OcrBackendBridge {
	return &OcrBackendBridge{impl: impl}
}

func (b *OcrBackendBridge) Name() string {
	return b.impl.Name()
}

func (b *OcrBackendBridge) Version() string {
	return b.impl.Version()
}

func (b *OcrBackendBridge) Initialize() error {
	return b.impl.Initialize()
}

func (b *OcrBackendBridge) Shutdown() error {
	return b.impl.Shutdown()
}

func (b *OcrBackendBridge) ProcessImage(image_bytes []byte, config OcrConfig) (ExtractedDocument, error) {
	return b.impl.ProcessImage(image_bytes, config)
}

func (b *OcrBackendBridge) ProcessImageFile(path string, config OcrConfig) (ExtractedDocument, error) {
	return b.impl.ProcessImageFile(path, config)
}

func (b *OcrBackendBridge) SupportsLanguage(lang string) bool {
	return b.impl.SupportsLanguage(lang)
}

func (b *OcrBackendBridge) BackendType() OcrBackendType {
	return b.impl.BackendType()
}

func (b *OcrBackendBridge) SupportedLanguages() []string {
	return b.impl.SupportedLanguages()
}

func (b *OcrBackendBridge) SupportsTableDetection() bool {
	return b.impl.SupportsTableDetection()
}

func (b *OcrBackendBridge) SupportsDocumentProcessing() bool {
	return b.impl.SupportsDocumentProcessing()
}

func (b *OcrBackendBridge) EmitsStructuredMarkdown() bool {
	return b.impl.EmitsStructuredMarkdown()
}

func (b *OcrBackendBridge) ProcessDocument(_path string, _config OcrConfig) (ExtractedDocument, error) {
	return b.impl.ProcessDocument(_path, _config)
}

//export goOcrBackendProcessImage
func goOcrBackendProcessImage(
	userData unsafe.Pointer,
	image_bytes *C.uint8_t,
	image_bytesLen C.size_t,
	config *C.char,
	outResult **C.char,
	outError **C.char,
) (ret C.int32_t) {

	defer func() {
		if r := recover(); r != nil {
			fmt.Fprintln(os.Stderr, "[OcrBackendBridge] host 'ProcessImage' panicked:", r)
			*outError = C.CString(fmt.Sprint(r))
			ret = 1
		}
	}()

	handle := cgo.Handle(uintptr(unsafe.Pointer(userData)))
	impl, ok := handle.Value().(OcrBackend)

	if !ok {
		fmt.Fprintln(os.Stderr, "[OcrBackendBridge] host 'ProcessImage' called with an invalid handle")
		*outError = C.CString("invalid handle")
		return 1
	}

	var goImage_bytes []byte
	if image_bytes != nil {
		goImage_bytes = unsafe.Slice((*byte)(unsafe.Pointer(image_bytes)), int(image_bytesLen))
	}
	var goConfig OcrConfig
	if config != nil {
		json.Unmarshal([]byte(C.GoString(config)), &goConfig)

	}

	// Call the method
	callbackResult, err := impl.ProcessImage(goImage_bytes, goConfig)

	if err != nil {
		cErr := C.CString(err.Error())
		*outError = cErr
		return 1
	}
	jsonBytes, _ := json.Marshal(callbackResult)
	cResult := C.CString(string(jsonBytes))
	*outResult = cResult
	return 0 // success
}

