// RegisterOcrBackend registers a OcrBackend implementation with the C runtime.
func RegisterOcrBackend(impl OcrBackend) error {
	bridge := NewOcrBackendBridge(impl)
	handle := cgo.NewHandle(bridge)
	// Build the C vtable by calling the C helper function.
	// This ensures function pointers are correctly populated in C, fixing ARM64 macOS issues.
	vtable := C.xberg_ocr_backend_vtable_new()
	if vtable == nil {
		return fmt.Errorf("failed to allocate %s vtable", impl.Name())
	}
	defer C.free(unsafe.Pointer(vtable))
	// Call C registration
	cName := C.CString(impl.Name())
	defer C.free(unsafe.Pointer(cName))

	var cErr *C.char
	rc := C.xberg_register_ocr_backend(
		cName,
		vtable,
		unsafe.Pointer(uintptr(handle)),
		&cErr,
	)

	if rc != 0 {
		msg := "failed to register OcrBackend"
		if cErr != nil {
			msg = C.GoString(cErr)
			C.xberg_free_string(cErr)
		}
		handle.Delete()
		return fmt.Errorf("%s", msg)
	}

	// Store handle by name for later cleanup on unregister
	ocr_backendRegistry.store(impl.Name(), handle)
	return nil
}

// UnregisterOcrBackend unregisters a OcrBackend implementation.
func UnregisterOcrBackend(name string) error {
	cName := C.CString(name)
	defer C.free(unsafe.Pointer(cName))
	var cErr *C.char
	rc := C.xberg_unregister_ocr_backend(cName, &cErr)

	if rc != 0 {
		msg := "failed to unregister OcrBackend"
		if cErr != nil {
			msg = C.GoString(cErr)
			C.xberg_free_string(cErr)
		}
		return fmt.Errorf("%s", msg)
	}

	// Delete the handle now that Rust has unregistered the plugin
	ocr_backendRegistry.delete(name)
	return nil
}

// ClearOcrBackends removes all registered OcrBackend implementations.
func ClearOcrBackends() error {
	var cErr *C.char
	rc := C.xberg_clear_ocr_backend(&cErr)

	if rc != 0 {
		msg := "failed to clear OcrBackend plugins"
		if cErr != nil {
			msg = C.GoString(cErr)
			C.free(unsafe.Pointer(cErr))
		}
		return fmt.Errorf("%s", msg)
	}

	// Delete all handles now that Rust has cleared all plugins
	ocr_backendRegistry.clear()
	return nil
}

// PostProcessor defines the Go interface for the PostProcessor trait.
type PostProcessor interface {
	// Name returns the plugin name.
	Name() string
	// Version returns the plugin version.
	Version() string
	// Initialize is called when the plugin is loaded.
	Initialize() error
	// Shutdown is called when the plugin is unloaded.
	Shutdown() error
	// process
	Process(result ExtractedDocument, config ExtractionConfig) error

	// processing_stage
	ProcessingStage() ProcessingStage

	// should_process
	ShouldProcess(_result ExtractedDocument, _config ExtractionConfig) bool

	// estimated_duration_ms
	EstimatedDurationMs(_result ExtractedDocument) uint64

	// priority
	Priority() int32
}

// PostProcessorBridge wraps a PostProcessor implementation and exposes it to the C plugin system.
type PostProcessorBridge struct {
	impl PostProcessor
}

// NewPostProcessorBridge creates a new Bridge wrapping the given implementation.
func NewPostProcessorBridge(impl PostProcessor) *PostProcessorBridge {
	return &PostProcessorBridge{impl: impl}
}

func (b *PostProcessorBridge) Name() string {
	return b.impl.Name()
}

func (b *PostProcessorBridge) Version() string {
	return b.impl.Version()
}

func (b *PostProcessorBridge) Initialize() error {
	return b.impl.Initialize()
}

func (b *PostProcessorBridge) Shutdown() error {
	return b.impl.Shutdown()
}

func (b *PostProcessorBridge) Process(result ExtractedDocument, config ExtractionConfig) error {
	return b.impl.Process(result, config)
}

func (b *PostProcessorBridge) ProcessingStage() ProcessingStage {
	return b.impl.ProcessingStage()
}

func (b *PostProcessorBridge) ShouldProcess(_result ExtractedDocument, _config ExtractionConfig) bool {
	return b.impl.ShouldProcess(_result, _config)
}

func (b *PostProcessorBridge) EstimatedDurationMs(_result ExtractedDocument) uint64 {
	return b.impl.EstimatedDurationMs(_result)
}

func (b *PostProcessorBridge) Priority() int32 {
	return b.impl.Priority()
}

