// TokenizerBackend defines the Go interface for the TokenizerBackend trait.
type TokenizerBackend interface {
	// Name returns the plugin name.
	Name() string
	// Version returns the plugin version.
	Version() string
	// Initialize is called when the plugin is loaded.
	Initialize() error
	// Shutdown is called when the plugin is unloaded.
	Shutdown() error
	// count_tokens
	CountTokens(text string) uint
}

// TokenizerBackendBridge wraps a TokenizerBackend implementation and exposes it to the C plugin system.
type TokenizerBackendBridge struct {
	impl TokenizerBackend
}

// NewTokenizerBackendBridge creates a new Bridge wrapping the given implementation.
func NewTokenizerBackendBridge(impl TokenizerBackend) *TokenizerBackendBridge {
	return &TokenizerBackendBridge{impl: impl}
}

